const newUser = { name: 'Bob', age: 30 };

fetch('https://api.example.com/users', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' }, // CRITICAL
  // Disassemble the object into a text string
  body: JSON.stringify(newUser) 
})
.then(response => {
  // Unpack the server's text string response back into a JS object
  return response.json(); 
})
.then(data => {
  console.log('Server replied with object:', data);
});
